import{_ as a,o as s,c as i,ag as t}from"./chunks/framework.uucRfDOW.js";const u=JSON.parse('{"title":"Security Helpers","description":"","frontmatter":{},"headers":[],"relativePath":"security.md","filePath":"security.md"}'),n={name:"security.md"};function o(r,e,h,l,p,c){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="security-helpers" tabindex="-1">Security Helpers <a class="header-anchor" href="#security-helpers" aria-label="Permalink to &quot;Security Helpers&quot;">​</a></h1><p>OmniGuard includes some helpful security features designed to give you more control over your application&#39;s state without any complexity.</p><h2 id="🔴-panic-mode" tabindex="-1">🔴 Panic Mode <a class="header-anchor" href="#🔴-panic-mode" aria-label="Permalink to &quot;🔴 Panic Mode&quot;">​</a></h2><p>Panic Mode is a simple fail-safe. If you need to quickly lock down your application (for example, during maintenance), OmniGuard can flip its logic to <strong>Deny Access</strong> for everyone except administrators.</p><h3 id="how-to-use-it" tabindex="-1">How to use it <a class="header-anchor" href="#how-to-use-it" aria-label="Permalink to &quot;How to use it&quot;">​</a></h3><p>In your <code>.env</code> file, just set:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OMNIGUARD_PANIC_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span></code></pre></div><h3 id="the-behavior" tabindex="-1">The Behavior: <a class="header-anchor" href="#the-behavior" aria-label="Permalink to &quot;The Behavior:&quot;">​</a></h3><ul><li><strong>Regular Users</strong>: All permission checks will return <code>false</code> instantly to keep your site safe.</li><li><strong>Administrators</strong>: Users defined in your <code>OMNIGUARD_SUPER_ADMIN_EMAIL</code> will still have access so they can fix things or perform maintenance.</li></ul><hr><h2 id="👻-ghost-mode-auditing-changes" tabindex="-1">👻 Ghost Mode (Auditing Changes) <a class="header-anchor" href="#👻-ghost-mode-auditing-changes" aria-label="Permalink to &quot;👻 Ghost Mode (Auditing Changes)&quot;">​</a></h2><p>Ghost Mode is a helpful way to test your permissions before they go &quot;live.&quot;</p><h3 id="the-behavior-1" tabindex="-1">The Behavior: <a class="header-anchor" href="#the-behavior-1" aria-label="Permalink to &quot;The Behavior:&quot;">​</a></h3><p>In Ghost Mode, OmniGuard evaluates the permissions as usual, but instead of actually denying access, it just logs what <em>would</em> have happened. This lets you see if your new roles are working correctly without affecting your users.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OMNIGUARD_GHOST_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span></code></pre></div><hr><h2 id="🎭-impersonation-act-as" tabindex="-1">🎭 Impersonation (Act As) <a class="header-anchor" href="#🎭-impersonation-act-as" aria-label="Permalink to &quot;🎭 Impersonation (Act As)&quot;">​</a></h2><p>OmniGuard includes a helpful impersonation service. This allows an administrator to &quot;Act As&quot; another user when troubleshooting something on their behalf.</p><h3 id="how-it-works" tabindex="-1">How it works: <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works:&quot;">​</a></h3><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> OmniGuard\\Services\\ImpersonationGuard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Helping a user with ID 10</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ImpersonationGuard</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">start</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($userId);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// When finished, go back to your admin account</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ImpersonationGuard</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><h3 id="staying-accountable" tabindex="-1">Staying Accountable: <a class="header-anchor" href="#staying-accountable" aria-label="Permalink to &quot;Staying Accountable:&quot;">​</a></h3><p>To keep things transparent, every time someone uses the &quot;Act As&quot; feature, OmniGuard creates a simple log entry so you always know who was helping whom and when it happened.</p><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Check out the complete <strong><a href="./usage.html">Usage Reference API</a></strong> to see how to use these helpers in your code.</p>`,25)])])}const k=a(n,[["render",o]]);export{u as __pageData,k as default};
